// ==========================================
// 2. Helper ToolsIcon Component
// ==========================================

const toolIconMap: Record<string, React.FC<IconProps>> = {
  openweather: OpenWeatherIcon,
  google: GoogleTranslateIcon,
  duckduckgo: DuckduckgoSearchIcon,
  wikipedia: WikipediaIcon,
  tavily_search: TavilySearchIcon,
  tavilysearch: TavilySearchIcon,
  math: CalculatorIcon,
  calculator: CalculatorIcon,
  siliconflow: SiliconFlowIcon,
  spark: SparkIcon,
  zhipuai: ZhipuAIIcon,
  web_search_pro: ZhipuAIIcon,
  serper: SerperIcon,
  workflow: WorkflowIcon,
  baidu: BaiduIcon,
  get_current_time: GetCurrentTimeIcon,
  mcp: McpIcon,
  bash: BashIcon,
  builtin: BashIcon,
};

export interface ToolsIconProps extends IconProps {
  name: string;
}

export const ToolsIcon: React.FC<ToolsIconProps> = ({ name = '', ...props }) => {
  const normalizedKey = name.toLowerCase().trim();
  
  // Also support fuzzy matching: e.g. "tavily" matches "tavily_search"
  let matchedKey = normalizedKey;
  if (normalizedKey.includes('tavily')) matchedKey = 'tavily_search';
  else if (normalizedKey.includes('weather')) matchedKey = 'openweather';
  else if (normalizedKey.includes('duckduckgo')) matchedKey = 'duckduckgo';
  else if (normalizedKey.includes('wikipedia')) matchedKey = 'wikipedia';
  else if (normalizedKey.includes('translate') || normalizedKey.includes('google')) matchedKey = 'google';
  else if (normalizedKey.includes('math') || normalizedKey.includes('calc')) matchedKey = 'math';
  else if (normalizedKey.includes('serper')) matchedKey = 'serper';
  else if (normalizedKey.includes('baidu')) matchedKey = 'baidu';
  else if (normalizedKey.includes('time')) matchedKey = 'get_current_time';
  else if (normalizedKey.includes('mcp')) matchedKey = 'mcp';
  else if (normalizedKey.includes('workflow')) matchedKey = 'workflow';
  else if (normalizedKey.includes('siliconflow')) matchedKey = 'siliconflow';
  else if (normalizedKey.includes('spark')) matchedKey = 'spark';
  else if (normalizedKey.includes('zhipu')) matchedKey = 'zhipuai';
  else if (normalizedKey.includes('builtin') || normalizedKey.includes('bash')) matchedKey = 'bash';

  const IconComp = toolIconMap[matchedKey];
  if (!IconComp) {
    // Default fallback icon: McpIcon as it represents an extensible tool
    return <McpIcon {...props} />;
  }
  return <IconComp {...props} />;
};
